// SPDX-License-Identifier: MITpackage tracingimport (	"errors"	"testing")func TestTracer_New(t *testing.T) {	tr := New()	if tr == nil {		t.Fatal("New() must not return nil")	}	if len(tr.Steps()) != 0 {		t.Error("new tracer must have zero steps")	}}func TestTracer_StartEnd(t *testing.T) {	tr := New()	s := tr.Start("step1")	s.End()	if s.Name != "step1" {		t.Errorf("expected step1, got %s", s.Name)	}	if s.EndedAt.Before(s.StartedAt) {		t.Error("ended_at must be after started_at")	}	if s.Error != "" {		t.Errorf("expected no error, got %s", s.Error)	}}func TestTracer_EndWithError(t *testing.T) {	tr := New()	s := tr.Start("failing")	s.EndWithError(errors.New("timeout"))	if s.Error != "timeout" {		t.Errorf("expected timeout, got %s", s.Error)	}}func TestTracer_StepsSnapshot(t *testing.T) {	tr := New()	tr.Start("a").End()	tr.Start("b").End()	steps := tr.Steps()	if len(steps) != 2 {		t.Fatalf("expected 2 steps, got %d", len(steps))	}	if steps[0].Name != "a" {		t.Errorf("expected step a, got %s", steps[0].Name)	}	if steps[1].Name != "b" {		t.Errorf("expected step b, got %s", steps[1].Name)	}}func TestTracer_StepsSnapshotIsCopy(t *testing.T) {	tr := New()	tr.Start("original").End()	steps := tr.Steps()	steps[0].Name = "mutated"	original := tr.Steps()	if original[0].Name != "original" {		t.Error("Steps() must return a copy, not a reference")	}}func TestTracer_MultipleSteps(t *testing.T) {	tr := New()	tr.Start("first").End()	tr.Start("second").End()	tr.Start("third").End()	if len(tr.Steps()) != 3 {		t.Errorf("expected 3 steps, got %d", len(tr.Steps()))	}	steps := tr.Steps()	if steps[0].Name != "first" || steps[1].Name != "second" || steps[2].Name != "third" {		t.Error("step order mismatch")	}}
